export function selectTrainingTasks(count = 6, avgAbility = 120): TrainingTask[] {
  const randomCount = Math.floor(count / 2);
  const fitCount = count - randomCount;

  // 1. Shuffle POOL to select random tasks and isolate the remaining pool
  const shuffled = [...POOL].sort(() => 0.5 - Math.random());
  const randomPicked = shuffled.slice(0, randomCount);
  const remaining = shuffled.slice(randomCount);

  // 2. Select the rest using the existing logic (closest difficulty)
  const scored = remaining.map((task) => {
    const diff = Math.abs(task.difficulty - avgAbility);
    return { task, score: diff };
  });
  scored.sort((a, b) => a.score - b.score);
  const fitPicked = scored.slice(0, fitCount).map((c) => c.task);

  return [...randomPicked, ...fitPicked];
}

export const KNOWLEDGE_COLORS: Record<KnowledgeType, string> = {
  DS: "#7c3aed",
  Graph: "#2563eb",
  String: "#10b981",
  Math: "#f59e0b",
  DP: "#ef4444"
};

export function knowledgeLabel(type: KnowledgeType): string {
  return KNOWLEDGE[type];
}
